from typing import Optional, Union


class ASTNode:
    def __init__(
        self,
        node_type: str,
        value: Optional[float] = None,
        op: Optional[str] = None,
        left: Optional["ASTNode"] = None,
        right: Optional["ASTNode"] = None,
        operand: Optional["ASTNode"] = None,
    ):
        self.type = node_type  # 'number', 'binop', 'unary'
        self.value = value  # for numbers
        self.op = op  # for operators
        self.left = left  # for binary operations
        self.right = right  # for binary operations
        self.operand = operand  # for unary operations


def __repr__(self) -> str:
    if self.type == "number":
        return f"ASTNode('number', value={self.value})"
    elif self.type == "binop":
        return f"ASTNode('binop', op='{self.op}', left={self.left}, right={self.right})"
    elif self.type == "unary":
        return f"ASTNode('unary', op='{self.op}', operand={self.operand})"
    return "ASTNode()"


def parse(expression: str) -> ASTNode:
    if not expression.strip():
        raise ValueError("Empty input expression")

    tokens = _tokenize(expression)
    result = _parse_expression(tokens)

    # Check for remaining tokens (would indicate unmatched parentheses)
    if tokens:
        raise ValueError("Unmatched parentheses")

    return result


def evaluate(node: ASTNode) -> float:
    if node is None:
        raise ValueError("Invalid AST node: None")

    if node.type == "number":
        if node.value is None:
            raise ValueError("Invalid AST node: number with no value")
        return float(node.value)
    elif node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Invalid AST node: binary operation with missing operands")

        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        elif node.op == "-":
            return left_val - right_val
        elif node.op == "*":
            return left_val * right_val
        elif node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val
    elif node.type == "unary":
        if node.operand is None:
            raise ValueError("Invalid AST node: unary operation with missing operand")

        operand_val = evaluate(node.operand)
        if node.op == "-":
            return -operand_val

    raise ValueError("Invalid AST node")


def _tokenize(expression: str) -> list:
    tokens = []
    i = 0
    n = len(expression)

    while i < n:
        c = expression[i]

        if c.isspace():
            i += 1
            continue

        if c.isdigit() or c == ".":
            # Parse number
            start = i
            while i < n and (expression[i].isdigit() or expression[i] == "."):
                i += 1
            num_str = expression[start:i]
            try:
                # Check if it's a valid number
                float(num_str)
                tokens.append(("NUMBER", num_str))
            except ValueError:
                raise ValueError(f"Invalid number format: {num_str}")
        elif c in "+-*/()":
            tokens.append(("OP", c))
            i += 1
        else:
            raise ValueError(f"Invalid token: {c}")

    return tokens


def _parse_expression(tokens: list) -> ASTNode:
    # We'll use recursive descent parsing with operator precedence
    return _parse_additive(tokens)


def _parse_additive(tokens: list) -> ASTNode:
    # Parse additive operations (+, -)
    left = _parse_multiplicative(tokens)

    while tokens and tokens[0][0] == "OP" and tokens[0][1] in "+-":
        op = tokens.pop(0)[1]
        right = _parse_multiplicative(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def _parse_multiplicative(tokens: list) -> ASTNode:
    # Parse multiplicative operations (*, /)
    left = _parse_unary(tokens)

    while tokens and tokens[0][0] == "OP" and tokens[0][1] in "*/":
        op = tokens.pop(0)[1]
        right = _parse_unary(tokens)
        left = ASTNode("binop", op=op, left=left, right=right)

    return left


def _parse_unary(tokens: list) -> ASTNode:
    # Parse unary minus
    if tokens and tokens[0][0] == "OP" and tokens[0][1] == "-":
        op = tokens.pop(0)[1]
        operand = _parse_primary(tokens)
        return ASTNode("unary", op=op, operand=operand)

    return _parse_primary(tokens)


def _parse_primary(tokens: list) -> ASTNode:
    # Parse primary expressions (numbers, parentheses)
    if not tokens:
        raise ValueError("Unexpected end of expression")

    token = tokens[0]

    if token[0] == "NUMBER":
        tokens.pop(0)
        return ASTNode("number", value=float(token[1]))

    elif token[0] == "OP" and token[1] == "(":
        tokens.pop(0)  # consume '('
        expr = _parse_expression(tokens)

        if not tokens or tokens[0][0] != "OP" or tokens[0][1] != ")":
            raise ValueError("Unmatched parentheses")

        tokens.pop(0)  # consume ')'
        return expr

    else:
        raise ValueError(f"Unexpected token: {token[1]}")
